-- Seed DV360 creatives (piezas) — reporte 'DV360 Video Drean'. Agregado por
-- mes × canal × categoria × rol × creative. Idempotente.
delete from dv360_creatives where source = 'dv360_report';

on conflict (mes, canal, categoria, rol, creative) do update set
  impresiones=excluded.impresiones, clicks=excluded.clicks, starts=excluded.starts,
  q25=excluded.q25, q50=excluded.q50, q75=excluded.q75, q100=excluded.q100,
  skips=excluded.skips, revenue_usd=excluded.revenue_usd, source=excluded.source, updated_at=now();
